import json
import threading
import tkinter as tk
from tkinter import ttk, messagebox

from ..config import load_config
from ..database import Database
from ..models import PlanStep, StepStatus
from ..services.claude_runner import run_claude
from ..services.json_parser import extract_json_steps
from ..services.context_builder import build_history_context


class ExtendPlanDialog(tk.Toplevel):
    """Dialog for extending an existing plan with new steps generated by Claude."""

    def __init__(self, parent: tk.Tk, db: Database, plan_id: str, on_saved=None):
        super().__init__(parent)
        self.db = db
        self.plan_id = plan_id
        self.plan = db.get_plan(plan_id)
        self.on_saved = on_saved
        self._preview_steps: list[dict] = []

        self.title(f"Extend Plan: {self.plan.name}")
        self.geometry("900x750")
        self.transient(parent)
        self.grab_set()

        self._existing_steps = db.get_steps_for_plan(plan_id)
        self._build_ui()

    def _build_ui(self):
        pad = {"padx": 8, "pady": 4}

        # Plan info (read-only)
        info_frame = ttk.LabelFrame(self, text="Plan Info")
        info_frame.pack(fill=tk.X, **pad)

        row = ttk.Frame(info_frame)
        row.pack(fill=tk.X, padx=4, pady=2)
        ttk.Label(row, text="Name:").pack(side=tk.LEFT)
        ttk.Label(row, text=self.plan.name, font=("Segoe UI", 9, "bold")).pack(side=tk.LEFT, padx=(4, 12))
        ttk.Label(row, text="Path:").pack(side=tk.LEFT)
        ttk.Label(row, text=self.plan.project_root or "(not set)").pack(side=tk.LEFT, padx=(4, 0))

        # Existing steps summary (compact treeview)
        ttk.Label(self, text="Existing Steps:").pack(anchor=tk.W, **pad)
        existing_frame = ttk.Frame(self)
        existing_frame.pack(fill=tk.X, **pad)

        cols = ("#", "Name", "Title", "Status")
        self.existing_tree = ttk.Treeview(existing_frame, columns=cols, show="headings",
                                          selectmode="none", height=min(6, max(3, len(self._existing_steps))))
        self.existing_tree.heading("#", text="#")
        self.existing_tree.heading("Name", text="Name")
        self.existing_tree.heading("Title", text="Title")
        self.existing_tree.heading("Status", text="Status")
        self.existing_tree.column("#", width=35, stretch=False)
        self.existing_tree.column("Name", width=120)
        self.existing_tree.column("Title", width=300)
        self.existing_tree.column("Status", width=80, stretch=False)

        # Color tags
        self.existing_tree.tag_configure("succeeded", background="#E8F5E9")
        self.existing_tree.tag_configure("failed", background="#FFEBEE")
        self.existing_tree.tag_configure("pending", background="")
        self.existing_tree.tag_configure("skipped", background="#F5F5F5")

        scroll = ttk.Scrollbar(existing_frame, orient=tk.VERTICAL, command=self.existing_tree.yview)
        self.existing_tree.configure(yscrollcommand=scroll.set)
        scroll.pack(side=tk.RIGHT, fill=tk.Y)
        self.existing_tree.pack(fill=tk.X, expand=False)

        for s in self._existing_steps:
            self.existing_tree.insert("", tk.END, values=(
                s.queue_position + 1, s.name, s.title, s.status.value,
            ), tags=(s.status.value,))

        # Description of what to add
        ttk.Label(self, text="What would you like to add or change?").pack(anchor=tk.W, **pad)
        self.desc_text = tk.Text(self, height=6, wrap=tk.WORD)
        self.desc_text.pack(fill=tk.X, **pad)

        # Generate button
        btn_row = ttk.Frame(self)
        btn_row.pack(fill=tk.X, **pad)
        self.generate_btn = ttk.Button(btn_row, text="Generate Steps", command=self._generate_steps)
        self.generate_btn.pack(side=tk.LEFT, padx=2)
        self.progress_var = tk.StringVar()
        ttk.Label(btn_row, textvariable=self.progress_var, foreground="blue").pack(side=tk.LEFT, padx=8)

        # Preview of new steps
        ttk.Label(self, text="New Steps Preview:").pack(anchor=tk.W, **pad)
        preview_frame = ttk.Frame(self)
        preview_frame.pack(fill=tk.BOTH, expand=True, **pad)

        preview_cols = ("Name", "Title", "Prompt")
        self.preview_tree = ttk.Treeview(preview_frame, columns=preview_cols, show="headings", selectmode="browse")
        self.preview_tree.heading("Name", text="Name")
        self.preview_tree.heading("Title", text="Title")
        self.preview_tree.heading("Prompt", text="Prompt")
        self.preview_tree.column("Name", width=120)
        self.preview_tree.column("Title", width=200)
        self.preview_tree.column("Prompt", width=400)
        p_scroll = ttk.Scrollbar(preview_frame, orient=tk.VERTICAL, command=self.preview_tree.yview)
        self.preview_tree.configure(yscrollcommand=p_scroll.set)
        p_scroll.pack(side=tk.RIGHT, fill=tk.Y)
        self.preview_tree.pack(fill=tk.BOTH, expand=True)
        self.preview_tree.bind("<Double-1>", lambda e: self._edit_preview_step())

        # Step action buttons
        step_btn_frame = ttk.Frame(self)
        step_btn_frame.pack(fill=tk.X, **pad)
        ttk.Button(step_btn_frame, text="Add Step", command=self._add_step_manual).pack(side=tk.LEFT, padx=2)
        ttk.Button(step_btn_frame, text="Edit Selected", command=self._edit_preview_step).pack(side=tk.LEFT, padx=2)
        ttk.Button(step_btn_frame, text="Delete Selected", command=self._delete_preview_step).pack(side=tk.LEFT, padx=2)

        # Bottom buttons
        bottom = ttk.Frame(self)
        bottom.pack(fill=tk.X, padx=8, pady=10)
        ttk.Button(bottom, text="Add to Plan", command=self._save_steps).pack(side=tk.RIGHT, padx=4)
        ttk.Button(bottom, text="Cancel", command=self.destroy).pack(side=tk.RIGHT, padx=4)

    def _build_existing_summary(self) -> str:
        """Build a text summary of existing steps for the Claude prompt."""
        lines = []
        for s in self._existing_steps:
            result_summary = ""
            if s.result:
                result_summary = s.result[:200].replace("\n", " ")
                if len(s.result) > 200:
                    result_summary += "..."
            lines.append(
                f"Step {s.queue_position + 1} ({s.name}): {s.title} [{s.status.value}]"
                + (f"\n  Result: {result_summary}" if result_summary else "")
            )
        return "\n".join(lines)

    def _generate_steps(self):
        description = self.desc_text.get("1.0", tk.END).strip()
        if not description:
            messagebox.showwarning("Missing Description", "Please describe what you want to add.", parent=self)
            return
        if not self.plan.project_root:
            messagebox.showwarning("Missing Path", "Plan has no project path set.", parent=self)
            return

        self.generate_btn.config(state=tk.DISABLED)
        self.progress_var.set("Asking Claude to generate new steps...")

        def _run():
            config = load_config()

            existing_summary = self._build_existing_summary()
            history_context = build_history_context(self.db, self.plan_id)
            next_position = len(self._existing_steps) + 1

            prompt = (
                "You are a project planner. An existing plan has already been partially or fully executed. "
                "The user wants to extend this plan with additional steps.\n\n"
                f"EXISTING PLAN: {self.plan.name}\n"
                f"EXISTING STEPS:\n{existing_summary}\n\n"
            )
            if history_context:
                prompt += f"{history_context}\n"
            prompt += (
                f"USER REQUEST:\n{description}\n\n"
                f"Generate ONLY the NEW steps needed (not the existing ones). "
                f"Number them starting from step {next_position}. "
                f"Return ONLY a JSON array where each element has: name (kebab-case), title (one-line), "
                f"prompt (detailed instructions that reference prior step results where relevant). "
                f"No markdown fences."
            )

            exit_code, stdout, stderr = run_claude(prompt, self.plan.project_root, config)
            self.after(0, lambda: self._on_claude_done(exit_code, stdout, stderr))

        threading.Thread(target=_run, daemon=True).start()

    def _on_claude_done(self, exit_code: int, stdout: str, stderr: str):
        self.generate_btn.config(state=tk.NORMAL)
        self.progress_var.set("")

        if exit_code != 0:
            messagebox.showerror("Claude Error", f"Claude exited with code {exit_code}.\n\n{stderr}", parent=self)
            return

        try:
            steps, warnings = extract_json_steps(stdout)
        except ValueError as e:
            messagebox.showerror("Parse Error", str(e), parent=self)
            return

        if warnings:
            self.progress_var.set("Parsed with fixups: " + "; ".join(warnings))

        self._preview_steps = steps
        self._refresh_preview()

    def _refresh_preview(self):
        for item in self.preview_tree.get_children():
            self.preview_tree.delete(item)
        for i, s in enumerate(self._preview_steps):
            prompt_preview = s.get("prompt", "")
            if len(prompt_preview) > 60:
                prompt_preview = prompt_preview[:60] + "..."
            self.preview_tree.insert("", tk.END, iid=str(i), values=(
                s.get("name", ""), s.get("title", ""), prompt_preview,
            ))

    def _add_step_manual(self):
        dlg = _MiniStepDialog(self)
        self.wait_window(dlg)
        if dlg.result:
            self._preview_steps.append(dlg.result)
            self._refresh_preview()

    def _edit_preview_step(self):
        sel = self.preview_tree.selection()
        if not sel:
            messagebox.showwarning("Edit Step", "No step selected.", parent=self)
            return
        idx = int(sel[0])
        existing = self._preview_steps[idx]
        dlg = _MiniStepDialog(self, existing=existing)
        self.wait_window(dlg)
        if dlg.result:
            self._preview_steps[idx] = dlg.result
            self._refresh_preview()

    def _delete_preview_step(self):
        sel = self.preview_tree.selection()
        if not sel:
            return
        idx = int(sel[0])
        del self._preview_steps[idx]
        self._refresh_preview()

    def _save_steps(self):
        if not self._preview_steps:
            messagebox.showwarning("No Steps", "No new steps to add.", parent=self)
            return

        # Append new steps starting after the last existing step
        start_pos = len(self._existing_steps)
        for i, s in enumerate(self._preview_steps):
            step = PlanStep(
                plan_id=self.plan_id,
                queue_position=start_pos + i,
                name=s.get("name", f"step-{start_pos + i + 1}"),
                title=s.get("title", ""),
                prompt=s.get("prompt", ""),
            )
            self.db.create_step(step)

        if self.on_saved:
            self.on_saved()
        self.destroy()


class _MiniStepDialog(tk.Toplevel):
    """Small dialog to add or edit a preview step."""

    def __init__(self, parent, existing: dict = None):
        super().__init__(parent)
        self.title("Edit Step" if existing else "Add Step")
        self.geometry("500x400")
        self.transient(parent)
        self.grab_set()
        self.result = None

        pad = {"padx": 8, "pady": 4}
        ttk.Label(self, text="Name (kebab-case):").pack(anchor=tk.W, **pad)
        self.name_var = tk.StringVar(value=existing.get("name", "") if existing else "")
        ttk.Entry(self, textvariable=self.name_var).pack(fill=tk.X, **pad)

        ttk.Label(self, text="Title:").pack(anchor=tk.W, **pad)
        self.title_var = tk.StringVar(value=existing.get("title", "") if existing else "")
        ttk.Entry(self, textvariable=self.title_var).pack(fill=tk.X, **pad)

        ttk.Label(self, text="Prompt:").pack(anchor=tk.W, **pad)
        self.prompt_text = tk.Text(self, height=10, wrap=tk.WORD)
        self.prompt_text.pack(fill=tk.BOTH, expand=True, **pad)
        if existing and existing.get("prompt"):
            self.prompt_text.insert("1.0", existing["prompt"])

        btn_frame = ttk.Frame(self)
        btn_frame.pack(fill=tk.X, **pad, pady=(4, 8))
        ttk.Button(btn_frame, text="Save", command=self._ok).pack(side=tk.RIGHT, padx=4)
        ttk.Button(btn_frame, text="Cancel", command=self.destroy).pack(side=tk.RIGHT, padx=4)

    def _ok(self):
        name = self.name_var.get().strip()
        title = self.title_var.get().strip()
        prompt = self.prompt_text.get("1.0", tk.END).strip()
        if not name:
            messagebox.showwarning("Missing Name", "Please enter a step name.", parent=self)
            return
        self.result = {"name": name, "title": title, "prompt": prompt}
        self.destroy()
